import React, { useState } from "react";

import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';
import SaveIcon from '@mui/icons-material/Save';

function Note(props) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedNote, setEditedNote] = useState({ title: props.title, content: props.content });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setEditedNote((prev) => ({ ...prev, [name]: value }));
  };

  const handleSave = () => {
    if (editedNote.content.trim() !== '') {
      props.editNote(props.id, editedNote);
      setIsEditing(false);
    }
  };

  return (
    <div className="note">
      {isEditing ? (
        <>
          <input 
            type="text" 
            name="title" 
            value={editedNote.title} 
            onChange={handleChange} 
            placeholder="Title"
            style={{ width: '100%', border: 'none', outline: 'none', marginBottom: '10px', fontSize: '1.1em', fontWeight: 'bold' }} 
          />
          <textarea 
            name="content" 
            value={editedNote.content} 
            onChange={handleChange} 
            placeholder="Take a note..."
            rows="3" 
            style={{ width: '100%', border: 'none', outline: 'none', fontSize: '1.1em', resize: 'none' }} 
          />
        </>
      ) : (
        <>
          <h1>{props.title}</h1>
          <p>{props.content}</p>
        </>
      )}
      
      <button onClick={() => props.deleteNote(props.id)}><DeleteIcon/></button>
      {isEditing ? (
        <button onClick={handleSave}><SaveIcon/></button>
      ) : (
        <button onClick={() => setIsEditing(true)}><EditIcon/></button>
      )}
    </div>
  );
}

export default Note;
